# pebble_studio_clearcache.py — clear weather-throttle timestamps from pypkjs localStorage.
#
# WHY: weather watchfaces commonly cache their last fetch and refuse to refetch
# until an internal window elapses — typically by storing Date.now() in
# localStorage and skipping weather for some minutes. So after the user changes
# Pebble Studio's *simulated* weather, the watch keeps showing the stale values
# until that window passes. This helper deletes those throttle stamps so the next
# launch refetches immediately — without touching the watchface's saved settings.
#
# pypkjs stores localStorage as `dbm.dumb`, one store per app UUID, EVERY value a
# string (LocalStorage.set does `self.storage[name] = str(value)`). A throttle
# stamp is therefore the string form of Date.now(): a 13-digit epoch-millisecond
# number. We delete ONLY keys whose value parses as such a number, leaving JSON
# settings blobs and every other value intact. Must run while the emulator is
# stopped — a live pypkjs holds the store open and caches its index in memory.
import dbm.dumb
import glob
import os
import sys

# Epoch-ms window ≈ 2001-09 .. 2033-05. A localStorage value inside it is
# overwhelmingly a Date.now() throttle stamp, not a user-entered setting.
EPOCH_MS_MIN = 1_000_000_000_000
EPOCH_MS_MAX = 2_000_000_000_000


def is_epoch_ms(value):
    """True iff `value` (bytes or str) is a bare epoch-millisecond number.

    Accepts both the integer form ("1781729836045") and the float form
    pypkjs actually writes ("1781729836045.0" — a JS number stringified through
    a Python float). Rejects JSON blobs, plain small numbers, and anything with a
    non-zero fractional part, so watchface settings are never mistaken for stamps."""
    if isinstance(value, (bytes, bytearray)):
        s = value.decode("utf-8", "replace")
    else:
        s = str(value)
    s = s.strip()
    head, dot, frac = s.partition(".")
    if not head.isdigit():               # rejects "", "-1", "1e12", JSON, words
        return False
    if dot and frac.strip("0") != "":    # only a zero fraction (".0", ".000") allowed
        return False
    try:
        n = float(s)
    except ValueError:
        return False
    return EPOCH_MS_MIN <= n < EPOCH_MS_MAX


def clear_store(dat_path):
    """Delete epoch-ms-valued keys from one `<uuid>.dat` dbm.dumb store.
    Returns the list of removed key names. May raise (e.g. dbm.error on a
    corrupt/half-written store); the `clear_root` caller catches per-store."""
    base = dat_path[:-4] if dat_path.endswith(".dat") else dat_path
    removed = []
    db = dbm.dumb.open(base, "w")
    try:
        for k in list(db.keys()):
            try:
                v = db[k]
            except Exception:
                continue
            if is_epoch_ms(v):
                removed.append(k.decode("utf-8", "replace") if isinstance(k, (bytes, bytearray)) else str(k))
                del db[k]
    finally:
        db.close()
    return removed


def clear_root(root):
    """Sweep every `<ver>/<board>/localstorage/<uuid>.dat` under `root`
    (the `<userData>/pebble-data/pebble-sdk` persist root). Returns
    {dat_path: [removed_keys]} for stores that changed."""
    cleared = {}
    pattern = os.path.join(root, "*", "*", "localstorage", "*.dat")
    for dat in glob.glob(pattern):
        try:
            r = clear_store(dat)
            if r:
                cleared[dat] = r
        except Exception as e:  # one bad store must not abort the sweep
            sys.stderr.write("clearcache: %s: %r\n" % (dat, e))
    return cleared


def _selftest():
    import json
    import tempfile
    d = tempfile.mkdtemp()
    base = os.path.join(d, "app")
    db = dbm.dumb.open(base, "c")
    db["TIMESTAMP"] = "1781729836045.0"        # REAL form pypkjs writes (float) -> go
    db["settings"] = json.dumps({"KEY_INVERT": 1, "x": 12})  # JSON blob -> keep
    db["count"] = "7"                           # small int -> keep
    db["nextRun"] = "1700000000000"             # integer epoch-ms stamp -> go
    db.close()
    removed = clear_store(base + ".dat")
    db = dbm.dumb.open(base, "r")
    keys = set(k.decode() for k in db.keys())
    db.close()
    assert set(removed) == {"TIMESTAMP", "nextRun"}, removed
    assert keys == {"settings", "count"}, keys
    assert is_epoch_ms("1781729836045.0") and is_epoch_ms(b"1700000000000")
    assert is_epoch_ms("1781729836045")          # bare integer form too
    assert not is_epoch_ms("7") and not is_epoch_ms("hello") and not is_epoch_ms('{"a":1}')
    assert not is_epoch_ms("999999999999")       # below window (< 1e12)
    assert not is_epoch_ms("1781729836045.5")    # non-zero fraction -> not a stamp
    assert not is_epoch_ms("1.78e12")            # scientific form -> not matched
    print("OK")


if __name__ == "__main__":
    if "--selftest" in sys.argv:
        _selftest()
    else:
        args = [a for a in sys.argv[1:] if not a.startswith("--")]
        root = args[0] if args else "."
        cleared = clear_root(root)
        total = sum(len(v) for v in cleared.values())
        print("clearcache: removed %d timestamp key(s) across %d store(s)" % (total, len(cleared)))
        for p, keys in cleared.items():
            print("  %s -> %s" % (p, ", ".join(keys)))
